using Microsoft.VisualStudio.TestTools.UnitTesting;
using Store;

namespace Store.Tests;

[TestClass]
public class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup() => _cart = new ShoppingCart();

    // ── AddItem ──────────────────────────────────────────────

    [TestMethod]
    public void AddItem_SingleItem_AppearsInCart()
    {
        _cart.AddItem("SKU-1", 2, 9.99m);

        Assert.AreEqual(1, _cart.Items.Count);
        Assert.AreEqual(2, _cart.Items["SKU-1"].Quantity);
        Assert.AreEqual(9.99m, _cart.Items["SKU-1"].Price);
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_QuantitiesAreAccumulated()
    {
        _cart.AddItem("SKU-1", 1, 5.00m);
        _cart.AddItem("SKU-1", 3, 5.00m);

        Assert.AreEqual(1, _cart.Items.Count);
        Assert.AreEqual(4, _cart.Items["SKU-1"].Quantity);
    }

    [TestMethod]
    public void AddItem_DifferentSkus_BothAppear()
    {
        _cart.AddItem("A", 1, 1.00m);
        _cart.AddItem("B", 2, 2.00m);

        Assert.AreEqual(2, _cart.Items.Count);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void AddItem_InvalidSku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(() => _cart.AddItem(sku!, 1, 1.00m));
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-1)]
    public void AddItem_InvalidQuantity_Throws(int qty)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(() => _cart.AddItem("SKU", qty, 1.00m));
    }

    [TestMethod]
    public void AddItem_NegativePrice_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(() => _cart.AddItem("SKU", 1, -0.01m));
    }

    [TestMethod]
    public void AddItem_ZeroPrice_Succeeds()
    {
        _cart.AddItem("FREE", 1, 0m);
        Assert.AreEqual(0m, _cart.Items["FREE"].Price);
    }

    // ── RemoveItem ───────────────────────────────────────────

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovedFromCart()
    {
        _cart.AddItem("SKU-1", 1, 5.00m);
        _cart.RemoveItem("SKU-1");

        Assert.AreEqual(0, _cart.Items.Count);
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_ThrowsKeyNotFound()
    {
        Assert.ThrowsException<KeyNotFoundException>(() => _cart.RemoveItem("MISSING"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("  ")]
    public void RemoveItem_InvalidSku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(() => _cart.RemoveItem(sku!));
    }

    // ── CalculateTotal ───────────────────────────────────────

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_SingleItem_ReturnsCorrectTotal()
    {
        _cart.AddItem("X", 3, 10.00m);
        Assert.AreEqual(30.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_MultipleItems_SumsCorrectly()
    {
        _cart.AddItem("A", 2, 5.00m);  // 10
        _cart.AddItem("B", 1, 7.50m);  //  7.50

        Assert.AreEqual(17.50m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterRemoval_ExcludesRemovedItem()
    {
        _cart.AddItem("A", 1, 10.00m);
        _cart.AddItem("B", 1, 20.00m);
        _cart.RemoveItem("A");

        Assert.AreEqual(20.00m, _cart.CalculateTotal());
    }

    // ── ApplyCoupon ──────────────────────────────────────────

    [TestMethod]
    public void ApplyCoupon_ValidCode_AppliesToTotal()
    {
        _cart.AddItem("X", 1, 100.00m);
        _cart.ApplyCoupon("SAVE10");

        Assert.AreEqual(90.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_Save20_Applies20PercentDiscount()
    {
        _cart.AddItem("X", 1, 50.00m);
        _cart.ApplyCoupon("SAVE20");

        Assert.AreEqual(40.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_Half_Applies50PercentDiscount()
    {
        _cart.AddItem("X", 2, 20.00m);
        _cart.ApplyCoupon("HALF");

        Assert.AreEqual(20.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_InvalidCode_Throws()
    {
        Assert.ThrowsException<ArgumentException>(() => _cart.ApplyCoupon("BOGUS"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void ApplyCoupon_NullOrEmptyCode_Throws(string? code)
    {
        Assert.ThrowsException<ArgumentException>(() => _cart.ApplyCoupon(code!));
    }

    [TestMethod]
    public void ApplyCoupon_DuplicateCoupon_Throws()
    {
        _cart.ApplyCoupon("SAVE10");
        Assert.ThrowsException<InvalidOperationException>(() => _cart.ApplyCoupon("SAVE10"));
    }

    [TestMethod]
    public void ApplyCoupon_MultipleDifferentCoupons_StackDiscounts()
    {
        _cart.AddItem("X", 1, 100.00m);
        _cart.ApplyCoupon("SAVE10"); // 10%
        _cart.ApplyCoupon("SAVE20"); // 20%  → total 30% off

        Assert.AreEqual(70.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_StackedDiscountsExceed100Percent_TotalIsZero()
    {
        _cart.AddItem("X", 1, 100.00m);
        _cart.ApplyCoupon("SAVE10"); // 10%
        _cart.ApplyCoupon("SAVE20"); // 20%
        _cart.ApplyCoupon("HALF");   // 50%  → 80% off, capped at 100%

        Assert.AreEqual(20.00m, _cart.CalculateTotal());
    }

    // ── End-to-end scenario ──────────────────────────────────

    [TestMethod]
    public void FullWorkflow_AddRemoveApplyCoupon_CalculatesCorrectly()
    {
        _cart.AddItem("WIDGET", 5, 4.00m);   // 20
        _cart.AddItem("GADGET", 2, 15.00m);  // 30
        _cart.RemoveItem("WIDGET");           // -20
        _cart.ApplyCoupon("SAVE10");          // 10% off 30 = 27

        Assert.AreEqual(27.00m, _cart.CalculateTotal());
    }
}

